package com.gdxgame;

import com.badlogic.gdx.backends.headless.HeadlessApplication;
import com.badlogic.gdx.backends.headless.HeadlessApplicationConfiguration;

public class Launcher {

    public static void main(String[] args) {
        String inputPath = null;

        for (String arg : args) {
            if (arg.startsWith("--input=")) {
                inputPath = arg.substring("--input=".length());
            }
        }

        if (inputPath == null) {
            System.err.println("Error: no --input=<file> argument provided");
            System.exit(1);
        }

        HeadlessApplicationConfiguration config = new HeadlessApplicationConfiguration();
        config.renderInterval = -1f; // render only when needed
        config.updatesPerSecond = -1;

        HeadlessApplication app = new HeadlessApplication(new GameListener(inputPath), config);

        // Block until the application exits
        try {
            Thread mainLoopThread = app.getMainLoopThread();
            if (mainLoopThread != null) {
                mainLoopThread.join();
            }
        } catch (InterruptedException e) {
            Thread.currentThread().interrupt();
        }
    }
}

